<?php
namespace Zclone\Core;
final class Queue { private ?\Redis $redis=null; public function __construct() { if (class_exists('Redis')) { $this->redis=new \Redis(); $this->redis->connect(Env::get('REDIS_HOST','127.0.0.1'), (int)Env::get('REDIS_PORT',6379), 1.0); } } public function push(string $queue,array $job): void { $json=json_encode($job); $this->redis ? $this->redis->lPush("q:$queue", $json) : file_put_contents(dirname(__DIR__,2)."/storage/queue-$queue.log", $json.PHP_EOL, FILE_APPEND); } public function pop(string $queue): ?array { if (!$this->redis) return null; $raw=$this->redis->rPop("q:$queue"); return $raw ? json_decode($raw,true) : null; } public function publish(string $channel,array $message): void { if ($this->redis) $this->redis->publish($channel, json_encode($message)); } }
